import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"安装 Fabric","description":"如何安装 Fabric 的手把手指南。","frontmatter":{"title":"安装 Fabric","description":"如何安装 Fabric 的手把手指南。","authors":["Benonardo","IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"zh_cn/1.21.8/players/installing-fabric.md","filePath":"versions/1.21.8/translated/zh_cn/players/installing-fabric.md","lastUpdated":1760721669000}`);var c={name:`zh_cn/1.21.8/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">安装 Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “安装 Fabric”">​</a></h1><p>本指南仅适用于官方的 Minecraft Launcher。 对于第三方启动器，应该参考它们的文档。</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. 下载 Fabric 安装器 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. 下载 Fabric 安装器”">​</a></h2><p>可以从 <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 网站</a> 下载 Fabric 安装器。</p><p>如果使用 Windows，下载 <code>.exe</code> 版本 （<code>Download For Windows</code>），因为不需要你的系统已安装 Java， 而是使用官方启动器附带的 Java。</p><p>对于 macOS 和 Linux，您应该下载 <code>.jar</code> 版本。 有时，此步骤之前需要安装 Java。</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. 运行 Fabric 安装器 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. 运行 Fabric 安装器”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>在运行安装器之前，请先关闭 Minecraft 和 Minecraft Launcher。</p></div><details class="details custom-block"><summary>macOS 用户须知</summary><p>在 macOS 上，可能需要右键点击下载目录中的 <code>.jar</code>，然后点击 <code>Open</code> 来运行。</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Fabric 安装器中的 MacOS 上下文菜单" loading="lazy"></p><p>问到“Are you sure you want to open it?”时，再次点击 <code>Open</code>。</p></details><p>打开安装器后，应该会看到这样的屏幕：</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="高亮 &quot;Install&quot; 的 Fabric 安装器" loading="lazy"></p><p>要安装 Fabric，只需从下拉列表中选择您的游戏版本，然后单击 <code>Install</code>。</p><div class="warning custom-block"><p class="custom-block-title">重要</p><p>确保选中“Create Profile”。</p></div><h2 id="3-you-re-done" tabindex="-1">3. 搞定！ <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. 搞定！”">​</a></h2><p>安装器完成后，可以打开 Minecraft Launcher，从左下角的下拉列表中选择 Fabric 配置文件，然后按下 <code>Play</code>！</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="选中了 Fabric 配置的 Minecraft Launcher" loading="lazy"></p><p>现在安装好了 Fabric，就可以向你的游戏添加模组了！ 更多信息请查看<a href="./finding-mods">寻找可信的模组</a>指南。</p><p>如果在遵循本指南时遇到任何问题，可以在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 频道中寻求帮助。</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};